"""Provider-neutral launch preflight validation and audit-event builders."""

from __future__ import annotations

from dataclasses import dataclass

from scc_cli.application.start_session import StartSessionPlan
from scc_cli.core.contracts import AgentLaunchSpec, AuditEvent
from scc_cli.core.enums import NetworkPolicy, SeverityLevel
from scc_cli.core.errors import (
    InvalidLaunchPlanError,
    LaunchPolicyBlockedError,
    LaunchPreflightError,
)
from scc_cli.ports.models import SandboxHandle


@dataclass(frozen=True)
class LaunchPreflightDecision:
    """Validated launch metadata used by the launch boundary."""

    provider_id: str
    network_policy: str
    required_destination_sets: tuple[str, ...]
    audit_event: AuditEvent


def evaluate_launch_preflight(plan: StartSessionPlan) -> LaunchPreflightDecision:
    """Validate that the prepared launch plan can start under the current policy."""
    spec = _validated_launch_spec(plan)
    provider_id = _validated_provider_id(spec.provider_id)
    required_destination_sets = _validated_required_destination_sets(spec.required_destination_sets)
    network_policy = _effective_network_policy(plan)

    if (
        network_policy == NetworkPolicy.LOCKED_DOWN_WEB.value
        and len(required_destination_sets) > 0
    ):
        raise LaunchPolicyBlockedError(
            provider_id=provider_id,
            network_policy=network_policy,
            required_destination_sets=required_destination_sets,
        )

    return LaunchPreflightDecision(
        provider_id=provider_id,
        network_policy=network_policy,
        required_destination_sets=required_destination_sets,
        audit_event=AuditEvent(
            event_type="launch.preflight.passed",
            message=f"Launch preflight passed for provider '{provider_id}'.",
            severity=SeverityLevel.INFO,
            subject=provider_id,
            metadata=_event_metadata(
                plan,
                provider_id=provider_id,
                network_policy=network_policy,
                required_destination_sets=required_destination_sets,
            ),
        ),
    )


def build_preflight_failure_event(
    plan: StartSessionPlan,
    error: LaunchPreflightError,
) -> AuditEvent:
    """Build the canonical audit event for a failed launch preflight."""
    provider_id = _safe_provider_id(plan)
    required_destination_sets = _safe_required_destination_sets(plan)
    network_policy = _effective_network_policy(plan)
    metadata = _event_metadata(
        plan,
        provider_id=provider_id,
        network_policy=network_policy,
        required_destination_sets=required_destination_sets,
    )
    metadata["failure_reason"] = error.user_message
    return AuditEvent(
        event_type="launch.preflight.failed",
        message=(
            f"Launch preflight failed for provider '{provider_id or 'unknown'}'."
        ),
        severity=SeverityLevel.ERROR,
        subject=provider_id or None,
        metadata=metadata,
    )


def build_launch_started_event(
    plan: StartSessionPlan,
    decision: LaunchPreflightDecision,
    handle: SandboxHandle,
) -> AuditEvent:
    """Build the canonical audit event for a successful runtime handoff."""
    metadata = _event_metadata(
        plan,
        provider_id=decision.provider_id,
        network_policy=decision.network_policy,
        required_destination_sets=decision.required_destination_sets,
    )
    metadata["sandbox_id"] = handle.sandbox_id
    if handle.name:
        metadata["sandbox_name"] = handle.name
    return AuditEvent(
        event_type="launch.started",
        message=f"Launch started for provider '{decision.provider_id}'.",
        severity=SeverityLevel.INFO,
        subject=decision.provider_id,
        metadata=metadata,
    )


def _validated_launch_spec(plan: StartSessionPlan) -> AgentLaunchSpec:
    spec = plan.agent_launch_spec
    if spec is None:
        raise InvalidLaunchPlanError(
            reason="Launch plan is missing provider launch metadata.",
        )
    return spec


def _validated_provider_id(provider_id: str) -> str:
    normalized = provider_id.strip()
    if normalized == "":
        raise InvalidLaunchPlanError(
            reason="Launch plan is missing provider identity.",
        )
    return normalized


def _validated_required_destination_sets(required_destination_sets: tuple[str, ...]) -> tuple[str, ...]:
    normalized: list[str] = []
    for destination_set in required_destination_sets:
        cleaned = destination_set.strip()
        if cleaned == "":
            raise InvalidLaunchPlanError(
                reason="Launch plan contains a blank required destination set name.",
            )
        normalized.append(cleaned)
    return tuple(normalized)


def _effective_network_policy(plan: StartSessionPlan) -> str:
    sandbox_spec = plan.sandbox_spec
    if sandbox_spec is None or sandbox_spec.network_policy is None:
        return NetworkPolicy.OPEN.value
    return sandbox_spec.network_policy


def _safe_provider_id(plan: StartSessionPlan) -> str:
    spec = plan.agent_launch_spec
    if spec is None:
        return ""
    return spec.provider_id.strip()


def _safe_required_destination_sets(plan: StartSessionPlan) -> tuple[str, ...]:
    spec = plan.agent_launch_spec
    if spec is None:
        return ()
    return tuple(destination_set.strip() for destination_set in spec.required_destination_sets)


def _event_metadata(
    plan: StartSessionPlan,
    *,
    provider_id: str,
    network_policy: str,
    required_destination_sets: tuple[str, ...],
) -> dict[str, str]:
    return {
        "provider_id": provider_id,
        "network_policy": network_policy,
        "required_destination_sets": ",".join(required_destination_sets),
        "workspace_path": str(plan.workspace_path),
        "session_name": plan.session_name or "",
        "team": plan.team or "",
    }

"""Finalize launch use case for start flows."""

from __future__ import annotations

from scc_cli.application.launch.preflight import (
    build_launch_started_event,
    build_preflight_failure_event,
    evaluate_launch_preflight,
)
from scc_cli.application.start_session import (
    StartSessionDependencies,
    StartSessionPlan,
    start_session,
)
from scc_cli.core.contracts import AuditEvent
from scc_cli.core.errors import (
    LaunchAuditUnavailableError,
    LaunchAuditWriteError,
    LaunchPreflightError,
)
from scc_cli.ports.audit_event_sink import AuditEventSink
from scc_cli.ports.models import SandboxHandle

FinalizeLaunchDependencies = StartSessionDependencies
FinalizeLaunchPlan = StartSessionPlan
FinalizeLaunchResult = SandboxHandle


def finalize_launch(
    plan: FinalizeLaunchPlan,
    *,
    dependencies: FinalizeLaunchDependencies,
) -> FinalizeLaunchResult:
    """Finalize a prepared launch plan by validating then starting the sandbox."""
    if _uses_preflight_seam(plan, dependencies):
        sink = dependencies.audit_event_sink
        if sink is None:
            raise LaunchAuditUnavailableError()
        try:
            decision = evaluate_launch_preflight(plan)
        except LaunchPreflightError as error:
            _append_audit_event(sink, build_preflight_failure_event(plan, error))
            raise
        _append_audit_event(sink, decision.audit_event)
        handle = start_session(plan, dependencies=dependencies)
        _append_audit_event(sink, build_launch_started_event(plan, decision, handle))
        return handle
    return start_session(plan, dependencies=dependencies)


def _uses_preflight_seam(
    plan: FinalizeLaunchPlan,
    dependencies: FinalizeLaunchDependencies,
) -> bool:
    return plan.agent_launch_spec is not None or dependencies.audit_event_sink is not None


def _append_audit_event(sink: AuditEventSink, event: AuditEvent) -> None:
    try:
        sink.append(event)
    except Exception as exc:  # pragma: no cover - defensive wrapper over sink adapters
        raise LaunchAuditWriteError(
            audit_destination=sink.describe_destination(),
            event_type=event.event_type,
            reason=str(exc),
        ) from exc

    if effective_config:
        from scc_cli.bootstrap import merge_mcp_servers

        settings = merge_mcp_servers(settings, effective_config)

    if not settings:
        return None

    settings_path = Path("/home/agent") / AGENT_CONFIG_DIR / "settings.json"
    return agent_runner.build_settings(settings, path=settings_path)


def _resolve_current_branch(workspace_path: Path, git_client: GitClient) -> str | None:
    try:
        if not git_client.is_git_repo(workspace_path):
            return None
        return git_client.get_current_branch(workspace_path)
    except (OSError, ValueError):
        return None


def _build_sandbox_spec(
    *,
    request: StartSessionRequest,
    resolver_result: ResolverResult,
    effective_config: EffectiveConfig | None,
    agent_settings: AgentSettings | None,
) -> SandboxSpec | None:
    if request.dry_run:
        return None
    return SandboxSpec(
        image=SANDBOX_IMAGE,
        workspace_mount=MountSpec(
            source=resolver_result.mount_root,
            target=resolver_result.mount_root,
        ),
        workdir=Path(resolver_result.container_workdir),
        network_policy=effective_config.network_policy if effective_config else None,
        continue_session=request.resume,
        force_new=request.fresh,
        agent_settings=agent_settings,
        org_config=request.org_config,
    )


def _build_agent_launch_spec(
    *,
    request: StartSessionRequest,
    agent_settings: AgentSettings | None,
    dependencies: StartSessionDependencies,
) -> AgentLaunchSpec | None:
    """Delegate launch spec construction to the provider adapter.

    Returns None when no provider is wired (backward compat) or in dry-run mode.
    The provider resolves its own argv, env, and artifact paths from the settings
    artifact already built by the sync/build_agent_settings path.
    """
    if request.dry_run:
        return None
    provider = dependencies.agent_provider
    if provider is None:
        return None
    settings_path = agent_settings.path if agent_settings is not None else None
    config: dict[str, Any] = {}
    if agent_settings is not None:
        config = dict(agent_settings.content)
    return provider.prepare_launch(
        config=config,
        workspace=request.workspace_path,
        settings_path=settings_path,
    )

